mapper.select:
SELECT parsed_benefit_id as parsedBenefitId, card_id2, title, category, benefit_type as benefitType, value, condition_text as conditionText, max_benefit_monthly as maxBenefitMonthly, min_spend_per_transaction as minSpendPerTransaction, pre_month_money_specific as preMonthMoneySpecific, description, created_time as createdTime, last_modified_time as lastModifiedTime FROM card_parsed_benefit WHERE card_id2 IN
#{cardId}
ORDER BY card_id2, parsed_benefit_id

mapper.delete:
DELETE FROM user_card_recommendations 
WHERE user_id = #{userId} 
AND base_card_id = #{baseCardId}

mapper.select:
SELECT COALESCE(SUM(mct.res_used_amount), 0)
FROM mydata_card_transactions mct
WHERE mct.user_id = #{userId}
AND mct.holding_id = #{holdingId}
AND mct.res_used_date BETWEEN DATE_FORMAT(#{startDate}, '%Y%m%d') AND DATE_FORMAT(#{endDate}, '%Y%m%d')
AND mct.res_cancel_yn IN ('N', '0')
